        System.Threading.Tasks.Task<SyncMetadataResponse> SyncMetadataAsync(string connectionIdentifier, SyncMetadataRequest syncMetadataRequest, System.Threading.CancellationToken cancellationToken = default(global::System.Threading.CancellationToken));

